    dummy = ListNode()
    curr = dummy
    while l1 and l2:
        if l1.val <= l2.val:
            curr.next = l1
            l1 = l1.next
        else:
            curr.next = l2
            l2 = l2.next
        curr = curr.next
    curr.next = l1 or l2
    return dummy.next

def merge_k_lists(lists: list[Optional[ListNode]]) -> Optional[ListNode]:
    heap: list[ListNode] = []
    for head in lists:
        if head:
            heapq.heappush(heap, head)
    dummy = ListNode()
    curr = dummy
    while heap:
        node = heapq.heappop(heap)
        curr.next = node
        curr = curr.next
        if node.next:
            heapq.heappush(heap, node.next)
    return dummy.next
