        pivot = nums[hi]
        store = lo
        for i in range(lo, hi):
            if nums[i] < pivot:
                nums[store], nums[i] = nums[i], nums[store]
                store += 1
        nums[store], nums[hi] = nums[hi], nums[store]
        if store == target:
            return nums[store]
        elif store < target:
            return quickselect(store + 1, hi)
        else:
            return quickselect(lo, store - 1)
    return quickselect(0, len(nums) - 1)

# Python stdlib approaches:
def kth_largest_heap(nums: list[int], k: int) -> int:
    return heapq.nlargest(k, nums)[-1]  # O(n + k log n)

def kth_largest_sorted(nums: list[int], k: int) -> int:
    return sorted(nums, reverse=True)[k - 1]  # O(n log n)
```

Quickselect: O(n) average, O(n^2) worst. heapq.nlargest: O(n + k log n). sorted: O(n log n).

