from collections import deque, defaultdict

def topo_sort_kahn(num_nodes: int, edges: list[tuple[int, int]]) -> list[int]:
    """Kahn's algorithm (BFS). edges: (prerequisite, dependent)."""
    graph: dict[int, list[int]] = defaultdict(list)
    in_degree = [0] * num_nodes
    for u, v in edges:
        graph[u].append(v)
        in_degree[v] += 1
    queue = deque(i for i in range(num_nodes) if in_degree[i] == 0)
    order: list[int] = []
    while queue:
        node = queue.popleft()
        order.append(node)
        for neighbor in graph[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)
    if len(order) != num_nodes:
        return []  # cycle detected
    return order

def topo_sort_dfs(num_nodes: int, edges: list[tuple[int, int]]) -> list[int]:
    graph: dict[int, list[int]] = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
    WHITE, GRAY, BLACK = 0, 1, 2
    color = [WHITE] * num_nodes
    order: list[int] = []
    has_cycle = False
    def dfs(node: int) -> None:
        nonlocal has_cycle
        if has_cycle:
            return
        color[node] = GRAY
        for neighbor in graph[node]:
            if color[neighbor] == GRAY:
                has_cycle = True
                return
            if color[neighbor] == WHITE:
                dfs(neighbor)
        color[node] = BLACK
        order.append(node)
    for i in range(num_nodes):
        if color[i] == WHITE:
            dfs(i)
    return order[::-1] if not has_cycle else []
```

Both O(V + E) time, O(V + E) space.

