import itertools
from typing import Generator

def permutations_lazy(items: list) -> Generator[tuple, None, None]:
    """Yield permutations one at a time without storing all of them."""
    if len(items) <= 1:
        yield tuple(items)
        return
    for i, item in enumerate(items):
        rest = items[:i] + items[i+1:]
        for perm in permutations_lazy(rest):
            yield (item,) + perm

def first_k_valid(items: list, predicate, k: int) -> list[tuple]:
    """Return first k permutations satisfying predicate."""
    gen = (p for p in itertools.permutations(items) if predicate(p))
    return list(itertools.islice(gen, k))

# Example: first 3 permutations of [1,2,3,4] where sum of first two > 4
result = first_k_valid([1,2,3,4], lambda p: p[0] + p[1] > 4, k=3)
