import itertools
from collections import Counter

# chain — flatten nested iterables
def flatten(nested: list[list[int]]) -> list[int]:
    return list(itertools.chain.from_iterable(nested))

# groupby — group consecutive identical elements (must be sorted first)
def group_consecutive(data: list[str]) -> dict[str, int]:
    sorted_data = sorted(data)
    return {k: len(list(g)) for k, g in itertools.groupby(sorted_data)}

# product — Cartesian product (replaces nested loops)
def all_pairs(rows: range, cols: range) -> list[tuple[int, int]]:
    return list(itertools.product(rows, cols))

# accumulate — running prefix sums / running max
def running_max(nums: list[int]) -> list[int]:
    return list(itertools.accumulate(nums, max))

# Sliding window with islice:
def sliding_windows(seq: list[int], k: int) -> list[tuple[int, ...]]:
    iters = [itertools.islice(iter(seq), i, None) for i in range(k)]
    return list(zip(*iters))
```

